void NePyInitStruct_Matrix(PyObject* PyOuterModule)
{
	const UScriptStruct* ScriptStruct = FNePyStructBase::SearchScriptStruct(TEXT("/Script/CoreUObject"), TEXT("Matrix"));
	if (ScriptStruct)
	{
		FNePyWrapperInitializer::Get().RegisterWrappedStructInitFunc(
			ScriptStruct, NePyNePyWrappedStructInit_Matrix);
	}
	else
	{
		PyTypeObject* NePyStructType = NePyNePyWrappedStructInit_Matrix(nullptr, NePyStructBaseGetType());
		Py_INCREF(NePyStructType);
		PyModule_AddObject(PyOuterModule, "Matrix", (PyObject*)NePyStructType);
	}
}

FNePyStruct_Matrix* NePyStructNew_Matrix(const FMatrix& InValue)
{
	PyTypeObject* PyType = &FNePyStructType_Matrix;
	FNePyStruct_Matrix* RetValue = (FNePyStruct_Matrix*)PyType->tp_alloc(PyType, 0);
	if (FNePyStruct_Matrix::Init(RetValue, nullptr, nullptr) < 0)
	{
		Py_DECREF(RetValue);
		return nullptr;
	}
	new(RetValue->Value) FMatrix(InValue);
	return RetValue;
}

